/**
 * Blog Post Page — Renders a single blog post from blog-posts.json.
 * Handles markdown-like body content (## headings, **bold**, ### subheadings, lists).
 * Public page, dark theme matching Aura Alpha design.
 */
import { useParams, Link, Navigate } from 'react-router-dom';
import usePageTitle from '../hooks/usePageTitle';
import SEO from '@/components/SEO';
import PublicNav from '@/components/PublicNav';
import PublicFooter from '@/components/PublicFooter';
import { tokens } from '../styles/tokens';
import blogPosts from '../data/blog-posts.json';
import s from './BlogPostPage.module.css';

const TAG_COLORS = {
  'algorithmic-trading': tokens.color.blue,
  'beginner': tokens.color.green,
  'education': tokens.color.amber,
  'machine-learning': tokens.color.purple,
  'regime-detection': tokens.color.cyan,
  'strategy': tokens.color.blue,
  'paper-trading': tokens.color.green,
  'live-trading': tokens.color.amber,
  'risk-management': tokens.color.purple,
  'strategies': tokens.color.cyan,
  '2026': tokens.color.green,
  'market-analysis': tokens.color.blue,
  'diversification': tokens.color.amber,
  'global-markets': tokens.color.cyan,
  'backtesting': tokens.color.amber,
  'engineering': tokens.color.purple,
  'congress-trading': tokens.color.green,
  'stock-act': tokens.color.amber,
  'automation': tokens.color.cyan,
};

function formatDate(dateStr) {
  const d = new Date(dateStr + 'T00:00:00');
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
}

/** Simple markdown-to-JSX renderer for blog content */
function renderMarkdown(body) {
  const lines = body.split('\n');
  const elements = [];
  let listItems = [];

  function flushList() {
    if (listItems.length > 0) {
      elements.push(
        <ul key={`list-${elements.length}`} className={s.mdList}>
          {listItems.map((item, i) => (
            <li key={i} className={s.mdListItem}>
              {renderInline(item)}
            </li>
          ))}
        </ul>
      );
      listItems = [];
    }
  }

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // H2
    if (line.startsWith('## ')) {
      flushList();
      elements.push(
        <h2 key={i} className={s.mdH2}>{line.slice(3)}</h2>
      );
      continue;
    }

    // H3
    if (line.startsWith('### ')) {
      flushList();
      elements.push(
        <h3 key={i} className={s.mdH3}>{line.slice(4)}</h3>
      );
      continue;
    }

    // List item (- or *)
    if (/^[-*] /.test(line.trim())) {
      listItems.push(line.trim().slice(2));
      continue;
    }

    // Empty line
    if (line.trim() === '') {
      flushList();
      continue;
    }

    // Regular paragraph
    flushList();
    elements.push(
      <p key={i} className={s.mdParagraph}>{renderInline(line)}</p>
    );
  }

  flushList();
  return elements;
}

/** Render inline markdown: **bold**, `code`, [links] */
function renderInline(text) {
  const parts = [];
  let remaining = text;
  let key = 0;

  while (remaining.length > 0) {
    // Bold
    const boldMatch = remaining.match(/\*\*(.+?)\*\*/);
    if (boldMatch && boldMatch.index !== undefined) {
      if (boldMatch.index > 0) {
        parts.push(<span key={key++}>{remaining.slice(0, boldMatch.index)}</span>);
      }
      parts.push(
        <strong key={key++} className={s.mdBold}>{boldMatch[1]}</strong>
      );
      remaining = remaining.slice(boldMatch.index + boldMatch[0].length);
      continue;
    }

    // Inline code
    const codeMatch = remaining.match(/`(.+?)`/);
    if (codeMatch && codeMatch.index !== undefined) {
      if (codeMatch.index > 0) {
        parts.push(<span key={key++}>{remaining.slice(0, codeMatch.index)}</span>);
      }
      parts.push(
        <code key={key++} className={s.mdCode}>{codeMatch[1]}</code>
      );
      remaining = remaining.slice(codeMatch.index + codeMatch[0].length);
      continue;
    }

    // No more matches — push rest as text
    parts.push(<span key={key++}>{remaining}</span>);
    break;
  }

  return parts;
}

export default function BlogPostPage() {
  const { slug } = useParams();
  const post = blogPosts.find(p => p.slug === slug);

  usePageTitle(post ? post.title : 'Post Not Found');

  if (!post) {
    return <Navigate to="/blog" replace />;
  }

  // Find adjacent posts for navigation
  const sorted = [...blogPosts].sort((a, b) => new Date(b.date) - new Date(a.date));
  const currentIdx = sorted.findIndex(p => p.slug === slug);
  const prevPost = currentIdx < sorted.length - 1 ? sorted[currentIdx + 1] : null;
  const nextPost = currentIdx > 0 ? sorted[currentIdx - 1] : null;

  return (
    <div className={s.page}>
      <SEO
        title={post.title}
        description={post.excerpt}
        keywords={post.tags.join(', ')}
        url={`https://auraalpha.cc/blog/${post.slug}`}
        type="article"
      />
      <PublicNav />

      <article className={s.article}>
        {/* Back link */}
        <Link to="/blog" className={s.backLink}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <line x1="19" y1="12" x2="5" y2="12" /><polyline points="12 19 5 12 12 5" />
          </svg>
          Back to Blog
        </Link>

        {/* Meta */}
        <div className={s.meta}>
          <span>{formatDate(post.date)}</span>
          <span className={s.metaSep}>|</span>
          <span>{post.readTime}</span>
          <span className={s.metaSep}>|</span>
          <span>{post.author}</span>
        </div>

        {/* Title */}
        <h1 className={s.title}>{post.title}</h1>

        {/* Tags — dynamic colors */}
        <div className={s.tagsRow}>
          {post.tags.map(tag => {
            const c = TAG_COLORS[tag] || tokens.color.blue;
            return (
              <span
                key={tag}
                className={s.tag}
                style={{
                  background: `color-mix(in srgb, ${c} 12%, transparent)`,
                  color: c,
                  border: `1px solid color-mix(in srgb, ${c} 20%, transparent)`,
                }}
              >
                {tag}
              </span>
            );
          })}
        </div>

        {/* Divider */}
        <div className={s.divider} />

        {/* Body */}
        <div className={s.body}>
          {renderMarkdown(post.body)}
        </div>

        {/* Divider */}
        <div className={s.dividerBottom} />

        {/* Post Navigation */}
        <div className={s.postNav}>
          {prevPost ? (
            <Link to={`/blog/${prevPost.slug}`} className={s.navLink}>
              <div className={s.navCard}>
                <div className={s.navLabel}>Previous</div>
                <div className={s.navTitle}>{prevPost.title}</div>
              </div>
            </Link>
          ) : <div className={s.navSpacer} />}

          {nextPost ? (
            <Link to={`/blog/${nextPost.slug}`} className={s.navLinkNext}>
              <div className={s.navCard}>
                <div className={s.navLabel}>Next</div>
                <div className={s.navTitle}>{nextPost.title}</div>
              </div>
            </Link>
          ) : <div className={s.navSpacer} />}
        </div>

        {/* CTA */}
        <div className={s.ctaCard}>
          <h3 className={s.ctaTitle}>Ready to trade smarter?</h3>
          <p className={s.ctaText}>
            Deploy 83 battle-tested strategies with ML regime detection across 14 global markets.
          </p>
          <Link to="/register" className={s.ctaButton}>
            Get Started Free
          </Link>
        </div>
      </article>

      <PublicFooter />
    </div>
  );
}
